import React from "react";

const GetInTouch = ({ heading, message1, email, message2, phoneNumber }) => {
  return (
    <>
      <h2 className="display-4 pb-3 text-center">{heading}</h2>
      <p className="lead text-center pb-3">
        {message}, <a className="text-decoration-none" href={`mailto:${email}`}>{email}</a>, {message2}, <a className="text-decoration-none" href={`mailto:${phoneNumber}`}>{phoneNumber}</a>.
      </p>
    </>
  );
};

export default GetInTouch;
